def get_polyominoes(n):
    # Create a 2D grid of size n x n
    grid = [[0]*n for _ in range(n)]

    def is_connected(piece):
        # Check if all squares are connected
        visited = set()
        stack = [piece[0]]
        while stack:
            x, y = stack.pop()
            if (x, y) not in visited:
                visited.add((x, y))
                for dx, dy in [(-1, 0), (1, 0), (0, -1), (0, 1)]:
                    nx, ny = x + dx, y + dy
                    if (nx, ny) in piece:
                        stack.append((nx, ny))
        return len(visited) == len(piece)

    def is_symmetric(piece1, piece2):
        # Check if two pieces are symmetric
        for _ in range(4):
            piece2 = {(y, -x) for x, y in piece2}
            if piece1 == piece2:
                return True
            piece2 = {(-x, y) for x, y in piece2}
            if piece1 == piece2:
                return True
        return False

    def get_polyominoes_recursive(grid, n, piece=None, x=0, y=0):
        if piece is None:
            piece = set()
        if n == 0:
            if is_connected(piece):
                yield piece
        else:
            for dx, dy in [(-1, 0), (1, 0), (0, -1), (0, 1), (0, 0)]:
                nx, ny = x + dx, y + dy
                if 0 <= nx < len(grid) and 0 <= ny < len(grid[0]) and (nx, ny) not in piece:
                    new_piece = piece | {(nx, ny)}
                    yield from get_polyominoes_recursive(grid, n-1, new_piece, nx, ny)

    polyominoes = set()
    for piece in get_polyominoes_recursive(grid, n):
        # Normalize the piece to the top-left corner
        min_x = min(x for x, y in piece)
        min_y = min(y for x, y in piece)
        piece = {(x-min_x, y-min_y) for x, y in piece}
